// @ts-nocheck
async function getTradeOffersFromSteam(e){try{if(!e)throw new Error("steamLoginSecure cookie не найден");const t=decodeURIComponent(e).split("||")[1];if(!t)throw new Error("access_token не найден в cookie");const s=`https://api.steampowered.com/IEconService/GetTradeOffers/v1/?${new URLSearchParams({access_token:t,get_sent_offers:"1",active_only:"1",language:"english"})}`,o=await fetch(s);if(!o.ok)throw new Error(`HTTP error ${o.status}`);const n=await o.json();return n.response.trade_offers_sent||[]}catch(e){throw console.error("💥 Ошибка в getTradeOffersFromSteam:",e),e}}chrome.runtime.onMessage.addListener(((e,t,s)=>{if("GET_STEAM_SESSION"===e.type){const e={sessionid:null,steamLoginSecure:null,steamid:null};if(window.g_sessionID)e.sessionid=window.g_sessionID;else{const t=document.cookie.split(";").find((e=>e.trim().startsWith("sessionid=")));e.sessionid=t?t.split("=")[1]:null}if(window.g_steamID)e.steamid=window.g_steamID;else{const t=document.cookie.split(";").find((e=>e.trim().startsWith("steamLoginSecure=")));if(t){e.steamLoginSecure=t.split("=")[1];const s=e.steamLoginSecure.match(/^(\d+)/);s&&(e.steamid=s[1])}if(!e.steamid){const t=window.location.href.match(/steamcommunity\.com\/(profiles|id)\/([^\/]+)/);e.steamid=t?t[2]:null}}s(e)}else if("GET_TRADE_OFFERS"===e.type)return getTradeOffersFromSteam(e.steamLoginSecure).then((e=>{s(e)})).catch((e=>{s(null)})),!0;return!0}));